using System.Reflection;

var agentsAsm = typeof(Microsoft.Agents.AI.ChatClientAgent).Assembly;
var abstractionsAsm = AppDomain.CurrentDomain.GetAssemblies()
    .FirstOrDefault(a => a.GetName().Name == "Microsoft.Agents.AI.Abstractions");

void DumpTypes(Assembly asm)
{
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
    {
        Console.WriteLine($"TYPE: {t.FullName} : {t.BaseType?.Name}");
        foreach (var c in t.GetConstructors())
            Console.WriteLine($"  CTOR({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"  PROP: {p.PropertyType.Name} {p.Name}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
            .Where(m => !m.IsSpecialName))
            Console.WriteLine($"  METHOD: {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}

Console.WriteLine("=== Microsoft.Agents.AI ===");
DumpTypes(agentsAsm);

if (abstractionsAsm != null)
{
    Console.WriteLine("\n=== Microsoft.Agents.AI.Abstractions ===");
    DumpTypes(abstractionsAsm);
}
