using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient through MEAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define the tools ---
var researchTools = new ResearchTools();

var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic:
        1. Use the SearchWeb tool to find relevant information (make several searches
           with different queries to get broad coverage).
        2. Use the SaveNote tool to record each key finding with its source.
        3. After gathering enough information, use GetNotes to review everything
           you collected, then produce a concise summary of the research.
        Always cite sources. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "Researches a topic using web search and produces a summary.",
    tools: tools);

// --- Prompt the user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching \"{topic}\"…\n");

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();

// ======================================================================
// Tool implementations
// ======================================================================
sealed class ResearchTools
{
    private readonly List<NoteEntry> _notes = [];
    private readonly HttpClient _http = new();

    /// <summary>Searches the web for a query and returns result snippets.</summary>
    [Description("Searches the web for a query and returns a list of result titles, snippets, and URLs.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍  Searching: \"{query}\"");

        try
        {
            // Use the DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1";

            var json = await _http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<SearchResult>();

            // Abstract / main result
            if (root.TryGetProperty("AbstractText", out var abs) &&
                abs.GetString() is { Length: > 0 } abstractText)
            {
                results.Add(new SearchResult(
                    root.GetProperty("Heading").GetString() ?? query,
                    abstractText,
                    root.GetProperty("AbstractURL").GetString() ?? ""));
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } snippet)
                    {
                        results.Add(new SearchResult(
                            snippet[..Math.Min(80, snippet.Length)],
                            snippet,
                            topic.TryGetProperty("FirstURL", out var u)
                                ? u.GetString() ?? ""
                                : ""));
                    }
                }
            }

            if (results.Count == 0)
            {
                results.Add(new SearchResult(
                    "No detailed results",
                    $"The search for \"{query}\" returned no structured results. Try rephrasing the query.",
                    ""));
            }

            Console.WriteLine($"       Found {results.Count} result(s).");
            return results;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"       Search error: {ex.Message}");
            return [new SearchResult("Error", $"Search failed: {ex.Message}", "")];
        }
    }

    /// <summary>Saves a research note.</summary>
    [Description("Saves a research note with a title, content, and source URL.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The note content / key finding")] string content,
        [Description("Source URL (if available)")] string source = "")
    {
        _notes.Add(new NoteEntry(title, content, source));
        Console.WriteLine($"  📝  Note saved: \"{title}\"");
        return $"Note \"{title}\" saved successfully. Total notes: {_notes.Count}.";
    }

    /// <summary>Returns all saved notes.</summary>
    [Description("Returns all research notes saved so far.")]
    public IReadOnlyList<NoteEntry> GetNotes()
    {
        Console.WriteLine($"  📋  Returning {_notes.Count} note(s).");
        return _notes.AsReadOnly();
    }
}

record SearchResult(string Title, string Snippet, string Url);
